from fastapi import FastAPI, File, UploadFile
from pydantic import BaseModel
import pickle

app = FastAPI()

class ModelUpload(BaseModel):
    model_id: str
    model_file: bytes

@app.post("/models/")
async def create_model(model_data: ModelUpload):
    try:
        with open("models/model.pkl", "wb") as f:
            f.write(model_data.model_file)
        loaded_model = pickle.load(open("models/model.pkl", "rb"))
        return {"message": "Model uploaded successfully"}
    except Exception as e:
        return {"message": str(e)}

@app.post("/predict/")
async def predict(model_id: str, data: list[float], file: UploadFile = File(None)):
    try:
        loaded_model = pickle.load(open(f"models/{model_id}.pkl", "rb"))
        prediction = loaded_model.predict(data)
        return {"prediction": prediction}
    except Exception as e:
        return {"message": str(e)}